<script>
(function () {
    function disableCardLinks() {
        var selectors = [
            '.wpr-magazine-grid a',
            '.wpr-magazine-grid [data-url]',
            '.wpr-grid a',
            '.wpr-grid [data-url]',
            '.wpr-posts a',
            '.wpr-posts [data-url]',
